const resp = $.steps.researchKeyword.response || {};
const data = resp.data || resp;
const results = data.results || [];

let competitorContent = '';
const competitorTitles = [];

results.slice(0, 5).forEach((r, i) => {
  const title = r.title || 'Untitled';
  const url = r.url || '';
  const text = (r.text || '').slice(0, 1500);
  competitorContent += 'Competitor ' + (i + 1) + ': ' + title + '\n';
  competitorContent += 'URL: ' + url + '\n';
  competitorContent += 'Content preview: ' + text + '\n\n';
  competitorTitles.push(title);
});

return { competitorContent, competitorTitles, competitorCount: results.length };

const keyword = $.input.keyword;
const wordCount = $.input.targetWordCount || 1500;
const research = $.steps.parseResearch.output;

let prompt = 'You are an expert SEO content writer. Write a comprehensive, SEO-optimized blog post that outranks the competition.\n\n';
prompt += 'TARGET KEYWORD: ' + keyword + '\n';
prompt += 'TARGET WORD COUNT: ' + wordCount + '\n\n';
prompt += 'COMPETITOR ANALYSIS:\n' + research.competitorContent + '\n';
prompt += 'COMPETITOR TITLES: ' + research.competitorTitles.join(', ') + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a title that is better than competitors (include target keyword)\n';
prompt += '- Write a meta description under 160 characters with the keyword\n';
prompt += '- Use H2 and H3 headings with keyword variations\n';
prompt += '- Include an introduction, 4-6 main sections, and conclusion\n';
prompt += '- Use HTML formatting (h2, h3, p, ul/li, strong)\n';
prompt += '- Add internal linking suggestions and a FAQ section\n';
prompt += '- Make content comprehensive, going beyond what competitors cover\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "SEO-optimized title",\n';
prompt += '  "metaDescription": "Under 160 chars with keyword",\n';
prompt += '  "content": "Full HTML blog post content",\n';
prompt += '  "headings": ["H2 heading 1", "H2 heading 2"],\n';
prompt += '  "wordCount": 1500,\n';
prompt += '  "primaryKeyword": "main keyword",\n';
prompt += '  "secondaryKeywords": ["related kw1", "related kw2"],\n';
prompt += '  "faqQuestions": ["FAQ question 1"],\n';
prompt += '  "seoScore": "estimated SEO readiness 1-10"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiWrite.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'SEO Post: ' + $.input.keyword, metaDescription: '', content: raw, headings: [], wordCount: 0, primaryKeyword: $.input.keyword, secondaryKeywords: [], faqQuestions: [], seoScore: 'N/A' }; }

const ai = $.steps.parseAI.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'SEO Blog Post Generated', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'Untitled') + '*' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Keyword:*\n' + (ai.primaryKeyword || 'N/A') },
  { type: 'mrkdwn', text: '*Word Count:*\n' + (ai.wordCount || 0) }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*SEO Score:*\n' + (ai.seoScore || 'N/A') + '/10' },
  { type: 'mrkdwn', text: '*Headings:*\n' + (ai.headings || []).length + ' sections' }
] });
blocks.push({ type: 'divider' });

if (ai.metaDescription) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Meta Description:*\n' + ai.metaDescription } });
}

if (ai.secondaryKeywords && ai.secondaryKeywords.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Secondary Keywords:*\n' + ai.secondaryKeywords.join(', ') } });
}

if (ai.headings && ai.headings.length > 0) {
  let outlineText = '*Post Outline:*\n';
  ai.headings.forEach((h, i) => { outlineText += (i + 1) + '. ' + h + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: outlineText.slice(0, 1500) } });
}

if (ai.faqQuestions && ai.faqQuestions.length > 0) {
  let faqText = '*FAQ Section:*\n';
  ai.faqQuestions.slice(0, 3).forEach(q => { faqText += '- ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: faqText.slice(0, 1000) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Research + Claude AI + Google Sheets' }] });

const fallback = 'SEO Post: ' + (ai.title || '') + ' (' + (ai.wordCount || 0) + ' words, score: ' + (ai.seoScore || 'N/A') + ')';
return { blocks, fallback };
